  "inlineSchema": "// Quality Dashboard — 공통 스키마 (QD·TRA 공유)\n// User, Feedback, FeedbackReply 및 공통 enum 정의\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../../lib/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nmodel User {\n  id              String     @id @default(cuid())\n  name            String\n  email           String     @unique\n  passwordHash    String\n  role            Role\n  status          UserStatus @default(PENDING)\n  statusReason    String?\n  restrictedUntil DateTime?\n  department      String?\n  employeeId      String?\n  phone           String?\n  nickname        String?\n  createdAt       DateTime   @default(now())\n\n  feedbacks       Feedback[]\n  feedbackReplies FeedbackReply[]\n  boardPosts      BoardPost[]\n  boardComments   BoardComment[]\n\n  // TRA 관계 (tra.prisma 모델 추가 시 활성화)\n  tenders       Tender[]\n  reviewActions ReviewHistory[]\n  comments      Comment[]\n}\n\nmodel Feedback {\n  id        String   @id @default(cuid())\n  author    User     @relation(fields: [authorId], references: [id])\n  authorId  String\n  content   String\n  imageUrls String?\n  createdAt DateTime @default(now())\n\n  replies FeedbackReply[]\n}\n\nmodel FeedbackReply {\n  id         String   @id @default(cuid())\n  feedback   Feedback @relation(fields: [feedbackId], references: [id])\n  feedbackId String\n  author     User     @relation(fields: [authorId], references: [id])\n  authorId   String\n  content    String\n  createdAt  DateTime @default(now())\n}\n\nenum Role {\n  PRACTITIONER // 실무자\n  TEAM_LEAD // 팀장\n  DIRECTOR // 부문장/임원\n  ADMIN // 시스템 관리자\n}\n\nenum UserStatus {\n  PENDING\n  ACTIVE\n  RESTRICTED\n  BANNED\n}\n\n// ─── 품질부문 게시판 ────────────────────────────────────────\n\nenum BoardCategory {\n  NOTICE // 공지\n  GENERAL // 일반\n}\n\nmodel BoardPost {\n  id        String         @id @default(cuid())\n  category  BoardCategory  @default(GENERAL)\n  pinned    Boolean        @default(false)\n  title     String\n  content   String\n  author    User           @relation(fields: [authorId], references: [id])\n  authorId  String\n  createdAt DateTime       @default(now())\n  updatedAt DateTime       @updatedAt\n  comments  BoardComment[]\n}\n\nmodel BoardComment {\n  id        String         @id @default(cuid())\n  post      BoardPost      @relation(fields: [postId], references: [id], onDelete: Cascade)\n  postId    String\n  author    User           @relation(fields: [authorId], references: [id])\n  authorId  String\n  content   String\n  parentId  String?\n  parent    BoardComment?  @relation(\"Replies\", fields: [parentId], references: [id], onDelete: Cascade)\n  replies   BoardComment[] @relation(\"Replies\")\n  createdAt DateTime       @default(now())\n}\n\n// TRA 전용 스키마 — Tender Review Assistant 모델\n// User·Feedback·FeedbackReply·Role·UserStatus는 common.prisma 참조\n\n// ─── 입찰 ────────────────────────────────────────────────\nmodel Tender {\n  id          String   @id @default(cuid())\n  title       String\n  createdAt   DateTime @default(now())\n  createdBy   User     @relation(fields: [createdById], references: [id])\n  createdById String\n\n  documents TenderDocument[]\n  analyses  Analysis[]\n}\n\nmodel TenderDocument {\n  id               String   @id @default(cuid())\n  tender           Tender   @relation(fields: [tenderId], references: [id])\n  tenderId         String\n  filename         String\n  storagePath      String\n  uploadedAt       DateTime @default(now())\n  isAnalysisSource Boolean  @default(true)\n\n  analyses Analysis[]\n}\n\n// ─── 분석 결과 ─────────────────────────────────────────────\n// 모든 AI 생성 결과는 status=DRAFT로만 생성 — 자동 확정 없음\nmodel Analysis {\n  id          String          @id @default(cuid())\n  tender      Tender          @relation(fields: [tenderId], references: [id])\n  tenderId    String\n  document    TenderDocument? @relation(fields: [documentId], references: [id])\n  documentId  String?\n  status      AnalysisStatus  @default(DRAFT)\n  submittedAt DateTime?\n  createdAt   DateTime        @default(now())\n  updatedAt   DateTime        @updatedAt\n\n  // 기검요청서 시스템 특성\n  voltage          String?\n  bilSil           String?\n  shortCircuit     String?\n  installCond      String?\n  groundConfig     String?\n  requiredCapacity String?\n\n  // AI 분석 메타데이터\n  ragChunkCount     Int     @default(0)\n  webContextApplied Boolean @default(false)\n  aiUsed            String?\n\n  // 부문장 전용\n  directorMemo String?\n  draftOpinion String?\n\n  requirements SpecRequirement[]\n  history      ReviewHistory[]\n  comments     Comment[]\n}\n\nenum AnalysisStatus {\n  DRAFT\n  REVIEWED\n  APPROVED\n}\n\n// ─── 추출 요구사항 ───────────────────────────────────────────\nmodel SpecRequirement {\n  id            String            @id @default(cuid())\n  analysis      Analysis          @relation(fields: [analysisId], references: [id])\n  analysisId    String\n  category      String\n  content       String\n  sourcePage    Int?\n  sourceText    String?\n  comply        ComplianceStatus?\n  remark        String?\n  isRisk        Boolean           @default(false)\n  isVE          Boolean           @default(false)\n  deviationType DeviationType?\n  deviationText String?\n\n  standards Standard[] @relation(\"RequirementToStandard\")\n}\n\nenum ComplianceStatus {\n  COMPLY\n  NON_COMPLY\n  TBD\n}\n\nenum DeviationType {\n  DEVIATION\n  CLARIFICATION\n  ASSUMPTION\n}\n\n// ─── 표준 규격 ────────────────────────────────────────────────\nmodel Standard {\n  id           String  @id\n  title        String\n  org          String\n  domain       String\n  subdomain    String?\n  productScope String\n  testType     String?\n  status       String  @default(\"active\")\n  edition      String?\n  pubDate      String?\n\n  parentSeriesId String?\n  parentSeries   Standard?  @relation(\"SeriesToParts\", fields: [parentSeriesId], references: [id])\n  parts          Standard[] @relation(\"SeriesToParts\")\n\n  requirements SpecRequirement[] @relation(\"RequirementToStandard\")\n}\n\n// ─── 리뷰 이력 ────────────────────────────────────────────────\n// append-only. 덮어쓰기·삭제 없음.\nmodel ReviewHistory {\n  id         String         @id @default(cuid())\n  analysis   Analysis       @relation(fields: [analysisId], references: [id])\n  analysisId String\n  user       User           @relation(fields: [userId], references: [id])\n  userId     String\n  action     ReviewAction\n  fromStatus AnalysisStatus\n  toStatus   AnalysisStatus\n  reason     String?\n  createdAt  DateTime       @default(now())\n}\n\nenum ReviewAction {\n  SUBMIT_FOR_REVIEW\n  REVIEW_APPROVE\n  REVIEW_REJECT\n  FINAL_APPROVE\n  FINAL_REJECT\n}\n\n// ─── 코멘트 ──────────────────────────────────────────────────\nmodel Comment {\n  id         String   @id @default(cuid())\n  analysis   Analysis @relation(fields: [analysisId], references: [id])\n  analysisId String\n  author     User     @relation(fields: [authorId], references: [id])\n  authorId   String\n  content    String\n  createdAt  DateTime @default(now())\n\n  parentId String?\n  parent   Comment?  @relation(\"CommentReplies\", fields: [parentId], references: [id])\n  replies  Comment[] @relation(\"CommentReplies\")\n}\n",
